import json
import re
import os

def parse_markdown_table(file_path):
    if not os.path.exists(file_path):
        return []
    with open(file_path, 'r') as f:
        lines = f.readlines()

    table_started = False
    rows = []
    for line in lines:
        if '|' in line:
            if not table_started:
                # Skip header and separator lines
                if '---' in line:
                    table_started = True
                    continue
                # Simple check to identify if it's a header row (contains 'Method' or 'Metric')
                if 'Method' in line or 'Metric' in line:
                    table_started = False # We'll wait for the separator
                    continue

            # Clean the row
            parts = [p.strip() for p in line.split('|') if p.strip()]
            if parts:
                rows.append(parts)
    return rows

def analyze_scope():
    # 1. Process api_endpoint_register.md
    endpoint_data = parse_markdown_table('api_endpoint_register.md')

    all_routes = []
    unauthenticated_routes = []

    # The table structure in api_endpoint_register.md for Pipeline Configs:
    # Method | Route | Auth | Added | Notes
    for row in endpoint_data:
        if len(row) >= 3 and (row[0] in ['GET', 'POST', 'PUT', 'DELETE']):
            route = row[1]
            auth = row[2]
            all_routes.append(route)
            if 'NONE' in auth.upper() or 'NOT REQUIRED' in auth.upper():
                unauthenticated_routes.append(route)

    # 2. Process customer_data_inventory.md
    inventory_data = parse_markdown_table('customer_data_inventory.md')

    total_configs = 0
    exposed_fields = []

    for row in inventory_data:
        # Summary Table: Metric | Value
        if len(row) == 2 and 'Total active pipeline configurations' in row[0]:
            try:
                total_configs = int(row[1].replace(',', ''))
            except ValueError:
                pass

        # Data Fields Table: Field | Type | Sensitivity | Stored in Config Object
        if len(row) >= 4 and row[0] != 'Field' and row[0] != '---':
            if 'Yes' in row[3]:
                exposed_fields.append(row[0])

    # Output JSON
    result = {
        "distinct_endpoint_count": len(set(all_routes)),
        "unauthenticated_routes": unauthenticated_routes,
        "exposed_data_fields": exposed_fields,
        "total_active_configs": total_configs,
        "sensitivity_classification": "high"
    }

    print(json.dumps(result, indent=2))

if __name__ == "__main__":
    analyze_scope()

import json
import re
import os

def parse_markdown_table(file_path):
    if not os.path.exists(file_path):
        return []
    with open(file_path, 'r') as f:
        content = f.read()

    # Find tables by looking for lines with pipes
    tables = []
    current_table = []
    for line in content.splitlines():
        if '|' in line:
            current_table.append(line)
        else:
            if current_table:
                tables.append(current_table)
                current_table = []
    if current_table:
        tables.append(current_table)

    # Convert raw lines to list of lists, cleaning whitespace and backticks
    processed_tables = []
    for table in tables:
        rows = []
        for line in table:
            # Remove leading/trailing pipes and split
            cells = [cell.strip().replace('`', '') for cell in line.strip('|').split('|')]
            rows.append(cells)
        processed_tables.append(rows)

    return processed_tables

def analyze_scope():
    # 1. Process api_endpoint_register.md
    endpoint_tables = parse_markdown_table('api_endpoint_register.md')

    all_routes = []
    unauthenticated_routes = []

    for table in endpoint_tables:
        # Look for the table that has 'Method' and 'Route' in header
        if len(table) > 0 and 'Method' in table[0] and 'Route' in table[0]:
            # Skip header (row 0) and separator (row 1)
            for row in table[2:]:
                if len(row) >= 3:
                    method = row[0]
                    route = row[1]
                    auth = row[2]
                    if method in ['GET', 'POST', 'PUT', 'DELETE']:
                        all_routes.append(route)
                        if 'NONE' in auth.upper():
                            unauthenticated_routes.append(route)

    # 2. Process customer_data_inventory.md
    inventory_tables = parse_markdown_table('customer_data_inventory.md')

    total_configs = 0
    exposed_fields = []

    for table in inventory_tables:
        # Summary Table: Metric | Value
        if len(table) > 0 and 'Metric' in table[0] and 'Value' in table[0]:
            for row in table[1:]:
                if len(row) >= 2 and 'Total active pipeline configurations' in row[0]:
                    # Remove commas and any non-numeric chars
                    val = re.sub(r'[^\d]', '', row[1])
                    if val:
                        total_configs = int(val)

        # Data Fields Table: Field | Type | Sensitivity | Stored in Config Object
        if len(table) > 0 and 'Field' in table[0] and 'Stored in Config Object' in table[0]:
            for row in table[1:]:
                if len(row) >= 4 and 'Yes' in row[3]:
                    exposed_fields.append(row[0])

    # Output JSON
    result = {
        "distinct_endpoint_count": len(set(all_routes)),
        "unauthenticated_routes": unauthenticated_routes,
        "exposed_data_fields": exposed_fields,
        "total_active_configs": total_configs,
        "sensitivity_classification": "high"
    }

    print(json.dumps(result, indent=2))

if __name__ == "__main__":
    analyze_scope()
